// COMPLETE, COMPILABLE C code
#include <stdio.h>
int main() {
    int T, n, q, x, y;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        scanf("%d %d", &n, &q);
        int A[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &A[i]);
        }
        printf("Case %d:\n", t + 1);
        for (int i = 0; i < q; i++) {
            scanf("%d %d", &x, &y);
            for (int j = 0; j < n; j++) {
                if (A[j] == x) {
                    A[j] = y;
                }
            }
            int value = 0;
            for (int j = 0; j < n - 1; j++) {
                value += abs(A[j] - A[j + 1]);
            }
            printf("%d\n", value);
        }
    }
    return 0;
}

