// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int t = 0; t < T; t++) {
            int n = sc.nextInt();
            int q = sc.nextInt();
            int[] A = new int[n];
            for (int i = 0; i < n; i++) {
                A[i] = sc.nextInt();
            }
            System.out.println("Case " + (t + 1) + ":");
            for (int i = 0; i < q; i++) {
                int x = sc.nextInt();
                int y = sc.nextInt();
                for (int j = 0; j < n; j++) {
                    if (A[j] == x) {
                        A[j] = y;
                    }
                }
                int value = 0;
                for (int j = 0; j < n - 1; j++) {
                    value += Math.abs(A[j] - A[j + 1]);
                }
                System.out.println(value);
            }
        }
    }
}

